## UserRepository findByNickname 성능 최적화 가이드

### 상황 분석
`findByNickname` 메서드가 느린 가장 일반적인 원인들:

1. **인덱스 미설정** - DB 레벨에서 nickname 컬럼 스캔
2. **N+1 쿼리** - 연관 엔티티(Profile, FollowInfo 등) 조회 시 반복 쿼리
3. **불필요한 컬럼** - 전체 엔티티를 조회할 필요가 없는 경우
4. **캐시 미적용** - 동일한 요청 반복 조회

---

## 1. 인덱스 미설정 문제 및 해결

### Before: 인덱스 없음
```kotlin
// UserEntity.kt - 인덱스 미지정
@Entity
@Table(catalog = "maum", name = "user")
class UserEntity(
    @Id
    val id: String = "",

    val nickname: String,  // 인덱스 없음!
    val email: String,
    val status: Int = 0,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)

// UserRepository.kt
interface UserRepository : JpaRepository<UserEntity, String> {
    fun findByNickname(nickname: String): UserEntity?
}
```

**문제점**: nickname이 인덱스 없이 전체 테이블 스캔(Full Table Scan) 발생

### After: 인덱스 추가
```kotlin
// UserEntity.kt - 유니크 인덱스 추가
@Entity
@Table(
    catalog = "maum",
    name = "user",
    indexes = [
        Index(name = "idx_nickname", columnList = "nickname", unique = true)
    ]
)
class UserEntity(
    @Id
    val id: String = "",

    @Column(unique = true, nullable = false, length = 50)
    val nickname: String,  // 인덱스 설정됨!

    val email: String,
    val status: Int = 0,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)

// UserRepository.kt - 동일
interface UserRepository : JpaRepository<UserEntity, String> {
    fun findByNickname(nickname: String): UserEntity?
}
```

**추가 필요한 DB 마이그레이션**:
```sql
-- 마이그레이션 파일 (V1__add_nickname_index.sql)
CREATE UNIQUE INDEX idx_nickname ON maum.user(nickname(50));
ALTER TABLE maum.user MODIFY COLUMN nickname VARCHAR(50) NOT NULL UNIQUE;
```

**효과**: 인덱스 B-Tree 탐색으로 O(log n) 성능 달성

---

## 2. N+1 쿼리 문제 및 해결

### Before: N+1 쿼리 발생
```kotlin
// UserEntity.kt
@Entity
@Table(catalog = "maum", name = "user")
class UserEntity(
    @Id
    val id: String = "",

    @Column(unique = true)
    val nickname: String,

    // 연관 엔티티들 - 기본 LAZY
    @OneToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "profile_id")
    val profile: ProfileEntity? = null,

    @OneToMany(mappedBy = "userId", fetch = FetchType.LAZY)
    val followers: List<FollowEntity> = emptyList(),
)

// UserRepository.kt
interface UserRepository : JpaRepository<UserEntity, String> {
    fun findByNickname(nickname: String): UserEntity?  // N+1 발생!
}

// Service에서 사용
class UserService(private val userRepository: UserRepository) {
    fun getUserDetail(nickname: String): UserDetailResponse {
        val user = userRepository.findByNickname(nickname) ?: throw UserNotFoundException()
        // profile 접근 -> 추가 쿼리 1회
        val profileName = user.profile?.name ?: "Unknown"
        // followers 접근 -> 추가 쿼리 N회
        val followerCount = user.followers.size  // SELECT COUNT(*) 또는 전체 로드
        return UserDetailResponse(user.id, profileName, followerCount)
    }
}
```

**문제점**: 
- 쿼리 1: User 조회
- 쿼리 2: Profile 조회 (접근 시)
- 쿼리 3+: Followers 조회 (접근 시)

### After: Fetch Join으로 해결
```kotlin
// UserRepository.kt - QueryDSL 사용
interface UserRepository : JpaRepository<UserEntity, String>, UserRepositoryCustom

interface UserRepositoryCustom {
    fun findByNicknameWithDetails(nickname: String): UserEntity?
}

// UserRepositoryImpl.kt
@Repository
class UserRepositoryImpl(
    private val queryFactory: JPAQueryFactory
) : UserRepositoryCustom {

    override fun findByNicknameWithDetails(nickname: String): UserEntity? {
        val qUser = QUserEntity.userEntity
        val qProfile = QProfileEntity.profileEntity
        val qFollow = QFollowEntity.followEntity

        return queryFactory
            .selectFrom(qUser)
            .leftJoin(qUser.profile, qProfile).fetchJoin()
            .leftJoin(qUser.followers, qFollow).fetchJoin()
            .where(qUser.nickname.eq(nickname))
            .distinct()  // 중복 제거 (OneToMany 때문에)
            .fetchOne()
    }
}

// UserRepository.kt 확장
interface UserRepository : JpaRepository<UserEntity, String>, UserRepositoryCustom {
    // JPA 메서드는 제거 (커스텀 구현 사용)
}

// Service에서 사용
class UserService(private val userRepository: UserRepository) {
    fun getUserDetail(nickname: String): UserDetailResponse {
        val user = userRepository.findByNicknameWithDetails(nickname) 
            ?: throw UserNotFoundException()
        // 이미 로드됨 - 추가 쿼리 없음!
        val profileName = user.profile?.name ?: "Unknown"
        val followerCount = user.followers.size
        return UserDetailResponse(user.id, profileName, followerCount)
    }
}
```

**생성되는 SQL**:
```sql
SELECT DISTINCT u.* FROM maum.user u
LEFT JOIN maum.profile p ON u.profile_id = p.id
LEFT JOIN maum.follow f ON u.id = f.user_id
WHERE u.nickname = 'john_doe';
```

**효과**: 쿼리 3개 -> 1개로 감소

---

## 3. 불필요한 컬럼 조회 문제 및 해결

### Before: 전체 엔티티 조회
```kotlin
// UserRepository.kt
interface UserRepository : JpaRepository<UserEntity, String> {
    fun findByNickname(nickname: String): UserEntity?  // 모든 컬럼 조회
}

// Service에서 닉네임 검증만 필요
class UserService(private val userRepository: UserRepository) {
    fun isNicknameAvailable(nickname: String): Boolean {
        val user = userRepository.findByNickname(nickname)
        return user == null  // ID만 필요한데 모든 컬럼을 로드!
    }
}
```

**문제점**: 대용량 컬럼(bio, preferences 등)까지 로드되어 메모리/네트워크 낭비

### After: Projection 사용
```kotlin
// Projection DTO
data class UserNicknameCheckDto(
    val id: String,
    val nickname: String,
)

// QClass 생성 (QueryDSL)
data class UserSimpleDto(
    val id: String,
    val nickname: String,
)

// UserRepository.kt
interface UserRepository : JpaRepository<UserEntity, String>, UserRepositoryCustom

interface UserRepositoryCustom {
    fun findIdByNickname(nickname: String): String?
    fun findSimpleByNickname(nickname: String): UserSimpleDto?
}

// UserRepositoryImpl.kt
@Repository
class UserRepositoryImpl(
    private val queryFactory: JPAQueryFactory
) : UserRepositoryCustom {

    // 방법 1: ID만 필요한 경우
    override fun findIdByNickname(nickname: String): String? {
        val qUser = QUserEntity.userEntity
        return queryFactory
            .select(qUser.id)
            .from(qUser)
            .where(qUser.nickname.eq(nickname))
            .fetchOne()
    }

    // 방법 2: 여러 필드 필요한 경우 DTO Projection
    override fun findSimpleByNickname(nickname: String): UserSimpleDto? {
        val qUser = QUserEntity.userEntity
        return queryFactory
            .select(
                Projections.constructor(
                    UserSimpleDto::class.java,
                    qUser.id,
                    qUser.nickname
                )
            )
            .from(qUser)
            .where(qUser.nickname.eq(nickname))
            .fetchOne()
    }
}

// Service에서 사용
class UserService(private val userRepository: UserRepository) {
    fun isNicknameAvailable(nickname: String): Boolean {
        val userId = userRepository.findIdByNickname(nickname)
        return userId == null  // ID만 로드!
    }

    fun getUserNicknameInfo(nickname: String): UserSimpleDto? {
        return userRepository.findSimpleByNickname(nickname)  // 필요한 필드만 로드!
    }
}
```

**생성되는 SQL**:
```sql
-- 방법 1: ID만 조회
SELECT u.id FROM maum.user u WHERE u.nickname = 'john_doe';

-- 방법 2: 특정 필드만 조회
SELECT u.id, u.nickname FROM maum.user u WHERE u.nickname = 'john_doe';
```

**효과**: 로드되는 컬럼 50% 이상 감소 가능

---

## 4. 캐시 미적용 문제 및 해결

### Before: 캐시 없음
```kotlin
// UserRepository.kt
interface UserRepository : JpaRepository<UserEntity, String> {
    fun findByNickname(nickname: String): UserEntity?
}

// Service - 동일한 요청이 DB를 반복 조회
class UserService(private val userRepository: UserRepository) {
    fun getUserInfo(nickname: String): UserResponse {
        // 요청 1, 2, 3 모두 DB 조회
        val user = userRepository.findByNickname(nickname)
        return UserResponse(user?.id, user?.nickname)
    }
}
```

**문제점**: 같은 사용자를 반복 조회할 때마다 DB 접근

### After: Redis 캐시 적용
```kotlin
// 설정: build.gradle.kts에 의존성 추가
dependencies {
