## 2. N+1 쿼리 문제 및 해결

### Before: N+1 쿼리 발생
```kotlin
// UserEntity.kt
@Entity
@Table(catalog = "maum", name = "user")
class UserEntity(
    @Id
    val id: String = "",

    @Column(unique = true)
    val nickname: String,

    // 연관 엔티티들 - 기본 LAZY
    @OneToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "profile_id")
    val profile: ProfileEntity? = null,

    @OneToMany(mappedBy = "userId", fetch = FetchType.LAZY)
    val followers: List<FollowEntity> = emptyList(),
)

// UserRepository.kt
interface UserRepository : JpaRepository<UserEntity, String> {
    fun findByNickname(nickname: String): UserEntity?  // N+1 발생!
}

// Service에서 사용
class UserService(private val userRepository: UserRepository) {
    fun getUserDetail(nickname: String): UserDetailResponse {
        val user = userRepository.findByNickname(nickname) ?: throw UserNotFoundException()
        // profile 접근 -> 추가 쿼리 1회
        val profileName = user.profile?.name ?: "Unknown"
        // followers 접근 -> 추가 쿼리 N회
        val followerCount = user.followers.size  // SELECT COUNT(*) 또는 전체 로드
        return UserDetailResponse(user.id, profileName, followerCount)
    }
}
```

**문제점**: 
- 쿼리 1: User 조회
- 쿼리 2: Profile 조회 (접근 시)
- 쿼리 3+: Followers 조회 (접근 시)

### After: Fetch Join으로 해결
```kotlin
// UserRepository.kt - QueryDSL 사용
interface UserRepository : JpaRepository<UserEntity, String>, UserRepositoryCustom

interface UserRepositoryCustom {
    fun findByNicknameWithDetails(nickname: String): UserEntity?
}

// UserRepositoryImpl.kt
@Repository
class UserRepositoryImpl(
    private val queryFactory: JPAQueryFactory
) : UserRepositoryCustom {

    override fun findByNicknameWithDetails(nickname: String): UserEntity? {
        val qUser = QUserEntity.userEntity
        val qProfile = QProfileEntity.profileEntity
        val qFollow = QFollowEntity.followEntity

        return queryFactory
            .selectFrom(qUser)
            .leftJoin(qUser.profile, qProfile).fetchJoin()
            .leftJoin(qUser.followers, qFollow).fetchJoin()
            .where(qUser.nickname.eq(nickname))
            .distinct()  // 중복 제거 (OneToMany 때문에)
            .fetchOne()
    }
}

// UserRepository.kt 확장
interface UserRepository : JpaRepository<UserEntity, String>, UserRepositoryCustom {
    // JPA 메서드는 제거 (커스텀 구현 사용)
}

// Service에서 사용
class UserService(private val userRepository: UserRepository) {
    fun getUserDetail(nickname: String): UserDetailResponse {
        val user = userRepository.findByNicknameWithDetails(nickname) 
            ?: throw UserNotFoundException()
        // 이미 로드됨 - 추가 쿼리 없음!
        val profileName = user.profile?.name ?: "Unknown"
        val followerCount = user.followers.size
        return UserDetailResponse(user.id, profileName, followerCount)
    }
}
```

