    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(unique = true, nullable = false, length = 50)
    val nickname: String,

    @Column(nullable = false, length = 100)
    val email: String,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "profile_id")
    val profile: ProfileEntity? = null,

    val status: Int = 0,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    @Column(columnDefinition = "datetime(3)")
    var updatedAt: LocalDateTime = LocalDateTime.now(),
) : Serializable

// DTO
data class UserDetailDto(
    val id: String,
    val nickname: String,
    val email: String,
    val profileName: String? = null,
)

// UserRepositoryCustom.kt
interface UserRepositoryCustom {
    fun findDetailByNicknameWithCache(nickname: String): UserDetailDto?
    fun findIdByNickname(nickname: String): String?
}

// UserRepositoryImpl.kt
@Repository
class UserRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
    @Qualifier("userCacheManager")
    private val cacheManager: CacheManager
) : UserRepositoryCustom {

    companion object {
        private const val CACHE_NAME = "user_detail_by_nickname"
    }

    override fun findDetailByNicknameWithCache(nickname: String): UserDetailDto? {
        // 캐시 확인
        val cached = cacheManager.getCache(CACHE_NAME)?.get(nickname, UserDetailDto::class.java)
        if (cached != null) return cached

        // DB 조회 (Fetch Join 포함)
        val qUser = QUserEntity.userEntity
        val qProfile = QProfileEntity.profileEntity

        val dto = queryFactory
            .select(
                Projections.constructor(
                    UserDetailDto::class.java,
                    qUser.id,
                    qUser.nickname,
                    qUser.email,
                    qProfile.name
                )
            )
            .from(qUser)
            .leftJoin(qUser.profile, qProfile).on(qUser.profile.id.eq(qProfile.id))
            .where(qUser.nickname.eq(nickname).and(qUser.status.eq(1)))  // 활성 사용자만
            .fetchOne()

        // 캐시 저장
        if (dto != null) {
            cacheManager.getCache(CACHE_NAME)?.put(nickname, dto)
        }

        return dto
    }

    override fun findIdByNickname(nickname: String): String? {
        val qUser = QUserEntity.userEntity
        return queryFactory
            .select(qUser.id)
            .from(qUser)
            .where(qUser.nickname.eq(nickname))
            .fetchOne()
    }
}

// UserRepository.kt
interface UserRepository : JpaRepository<UserEntity, String>, UserRepositoryCustom

// UserService.kt
@Service
class UserService(
    private val userRepository: UserRepository,
    private val cacheManager: CacheManager
) {

    fun getUserDetail(nickname: String): UserDetailDto {
        return userRepository.findDetailByNicknameWithCache(nickname)
            ?: throw UserNotFoundException("User not found: $nickname")
    }

    fun isNicknameAvailable(nickname: String): Boolean {
        return userRepository.findIdByNickname(nickname) == null
    }

    fun updateUserNickname(userId: String, newNickname: String) {
